import axios from 'axios';
import React, { useEffect, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useGetAllProductsQuery } from './MyorderApi';

const MyOrder = () => {
  const [renderData, setRenderData] = useState();
  var userid= sessionStorage.getItem("UserInfoID")

 

  

        const url = `http://localhost:1313/myorder/${userid}`

     
    useEffect(() => {
      const fetchData = async () => {
        await fetch(`http://localhost:1313/myorder/${userid}`)
          .then(async (res) => {
            const data = await res.json();
            setRenderData(data?.data);
          })
          .catch((err) => {
            console.log("err", err);
          });
      };
      fetchData();
    }, []);
    
 
  return (
    <div>
      my order {renderData}
    </div>
  )
}

export default MyOrder
